$outPath = 'c:\Users\SohaibAli\Videos\Development\AnalystDevelopmentFrontend\src\page-components\KnowledgeBasePage.tsx'  
Set-Content -Path $outPath -Value "'use client';" -Encoding UTF8  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "import React, { useState, useEffect, useCallback, useMemo } from 'react';"  
Add-Content -Path $outPath -Value "import {"  
Add-Content -Path $outPath -Value "  Database,"  
Add-Content -Path $outPath -Value "  FileText,"  
Add-Content -Path $outPath -Value "  Search,"  
Add-Content -Path $outPath -Value "  Upload,"  
Add-Content -Path $outPath -Value "  FolderOpen,"  
Add-Content -Path $outPath -Value "  HardDrive,"  
Add-Content -Path $outPath -Value "  Loader2,"  
Add-Content -Path $outPath -Value "  AlertCircle,"  
Add-Content -Path $outPath -Value "  RefreshCw,"  
Add-Content -Path $outPath -Value "  Bookmark,"  
Add-Content -Path $outPath -Value "  BookmarkCheck,"  
Add-Content -Path $outPath -Value "  Sparkles,"  
Add-Content -Path $outPath -Value "  MessageSquarePlus,"  
Add-Content -Path $outPath -Value "  Clock,"  
Add-Content -Path $outPath -Value "  TrendingUp,"  
Add-Content -Path $outPath -Value "  BookOpen,"  
Add-Content -Path $outPath -Value "  X,"  
Add-Content -Path $outPath -Value "  CheckCircle2,"  
Add-Content -Path $outPath -Value "  AlertTriangle,"  
Add-Content -Path $outPath -Value "} from 'lucide-react';" 
Add-Content -Path $outPath -Value "import kbApi from '@/lib/kbApi';"  
Add-Content -Path $outPath -Value "import type { KBDocument, KBStats } from '@/types/kb';"  
Add-Content -Path $outPath -Value "import { useTheme } from '@/contexts/ThemeContext';"  
Add-Content -Path $outPath -Value "import { useResponsive } from '@/hooks/useResponsive';"  
Add-Content -Path $outPath -Value "import FeedbackModal from '@/components/FeedbackModal';"  
Add-Content -Path $outPath -Value "import KBFileViewerModal from '@/components/knowledge/KBFileViewerModal';" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "type TabId = 'discover' ^| 'documents' ^| 'upload';"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "const TABS: { id: TabId; label: string; icon: React.ElementType }[] = ["  
Add-Content -Path $outPath -Value "  { id: 'discover', label: 'DISCOVER', icon: Sparkles },"  
Add-Content -Path $outPath -Value "  { id: 'documents', label: 'DOCUMENTS', icon: FileText },"  
Add-Content -Path $outPath -Value "  { id: 'upload', label: 'UPLOAD', icon: Upload },"  
Add-Content -Path $outPath -Value "];" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "function formatFileSize(bytes: number ^| null ^| undefined) {"  
Add-Content -Path $outPath -Value "  const n = Number(bytes ?? 0);"  
Add-Content -Path $outPath -Value "  if (n ^< 1024) return n + ' B';"  
Add-Content -Path $outPath -Value "  if (n ^< 1024 * 1024) return (n / 1024).toFixed(1) + ' KB';"  
Add-Content -Path $outPath -Value "  return (n / (1024 * 1024)).toFixed(2) + ' MB';"  
Add-Content -Path $outPath -Value "}" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "function getExt(filename: string) {"  
Add-Content -Path $outPath -Value "  return filename.split('.').pop()?.toLowerCase() ^|^| '';"  
Add-Content -Path $outPath -Value "}"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "function getFileColor(filename: string): string {"  
Add-Content -Path $outPath -Value "  const ext = getExt(filename);"  
Add-Content -Path $outPath -Value "  switch (ext) {"  
Add-Content -Path $outPath -Value "    case 'pdf': return '#ef4444';"  
Add-Content -Path $outPath -Value "    case 'doc': case 'docx': return '#3b82f6';"  
Add-Content -Path $outPath -Value "    case 'txt': case 'md': return '#22c55e';"  
Add-Content -Path $outPath -Value "    case 'csv': case 'xlsx': case 'xls': return '#22c55e';"  
Add-Content -Path $outPath -Value "    case 'json': case 'xml': case 'html': return '#f59e0b';"  
Add-Content -Path $outPath -Value "    default: return '#9ca3af';"  
Add-Content -Path $outPath -Value "  }"  
Add-Content -Path $outPath -Value "}" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "const catColors: Record^<string, { bg: string; text: string }^> = {"  
Add-Content -Path $outPath -Value "  afl: { bg: 'rgba(254,192,15,0.12)', text: 'var(--accent)' },"  
Add-Content -Path $outPath -Value "  strategy: { bg: 'rgba(34,197,94,0.12)', text: '#22c55e' },"  
Add-Content -Path $outPath -Value "  indicator: { bg: 'rgba(99,102,241,0.12)', text: '#818cf8' },"  
Add-Content -Path $outPath -Value "  documentation: { bg: 'rgba(59,130,246,0.12)', text: '#3b82f6' },"  
Add-Content -Path $outPath -Value "  general: { bg: 'rgba(156,163,175,0.12)', text: '#9ca3af' },"  
Add-Content -Path $outPath -Value "};" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "interface UploadItem {"  
Add-Content -Path $outPath -Value "  file: File;"  
Add-Content -Path $outPath -Value "  status: 'pending' ^| 'uploading' ^| 'processing' ^| 'ready' ^| 'error';"  
Add-Content -Path $outPath -Value "  documentId?: string;"  
Add-Content -Path $outPath -Value "  chunkCount?: number;"  
Add-Content -Path $outPath -Value "  error?: string;"  
Add-Content -Path $outPath -Value "}" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "export function KnowledgeBasePage() {"  
Add-Content -Path $outPath -Value "  const { resolvedTheme } = useTheme();"  
Add-Content -Path $outPath -Value "  const { isMobile, isTablet } = useResponsive();"  
Add-Content -Path $outPath -Value "  const isDark = resolvedTheme === 'dark';"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const colors = useMemo("  
Add-Content -Path $outPath -Value "    () =^> ({"  
Add-Content -Path $outPath -Value "      background: 'var(--bg)',"  
Add-Content -Path $outPath -Value "      cardBg: 'var(--bg-card)',"  
Add-Content -Path $outPath -Value "      inputBg: 'var(--bg-raised)',"  
Add-Content -Path $outPath -Value "      border: 'var(--border)',"  
Add-Content -Path $outPath -Value "      text: 'var(--text)',"  
Add-Content -Path $outPath -Value "      textMuted: 'var(--text-muted)',"  
Add-Content -Path $outPath -Value "      hoverBg: 'var(--bg-card-hover)',"  
Add-Content -Path $outPath -Value "      accent: 'var(--accent)',"  
Add-Content -Path $outPath -Value "      shadow: 'var(--shadow-card)',"  
Add-Content -Path $outPath -Value "    }),"  
Add-Content -Path $outPath -Value "    [],"  
Add-Content -Path $outPath -Value "  );" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const [documents, setDocuments] = useState^<KBDocument[]^>([]);"  
Add-Content -Path $outPath -Value "  const [stats, setStats] = useState^<KBStats ^| null^>(null);"  
Add-Content -Path $outPath -Value "  const [loading, setLoading] = useState(true);"  
Add-Content -Path $outPath -Value "  const [error, setError] = useState('');"  
Add-Content -Path $outPath -Value "  const [activeTab, setActiveTab] = useState^<TabId^>('discover');"  
Add-Content -Path $outPath -Value "  const [activeCategory, setActiveCategory] = useState('all');"  
Add-Content -Path $outPath -Value "  const [searchQuery, setSearchQuery] = useState('');"  
Add-Content -Path $outPath -Value "  const [viewerDoc, setViewerDoc] = useState^<KBDocument ^| null^>(null);"  
Add-Content -Path $outPath -Value "  const [bookmarkedIds, setBookmarkedIds] = useState^<Set^<string^>^>(new Set());"  
Add-Content -Path $outPath -Value "  const [showFeedback, setShowFeedback] = useState(false);"  
Add-Content -Path $outPath -Value "  const [uploadItems, setUploadItems] = useState^<UploadItem[]^>([]);"  
Add-Content -Path $outPath -Value "  const [dragOver, setDragOver] = useState(false);"  
Add-Content -Path $outPath -Value "  const fileInputRef = React.useRef^<HTMLInputElement^>(null);"  
Add-Content -Path $outPath -Value "  const pollingRefs = React.useRef^<Map^<string, ReturnType^<typeof setInterval^>^>^>(new Map());" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const loadData = useCallback(async () =^> {"  
Add-Content -Path $outPath -Value "    setLoading(true);"  
Add-Content -Path $outPath -Value "    setError('');"  
Add-Content -Path $outPath -Value "    try {"  
Add-Content -Path $outPath -Value "      const [filesRes, statsRes] = await Promise.all(["  
Add-Content -Path $outPath -Value "        kbApi.listFiles({ limit: 200 }),"  
Add-Content -Path $outPath -Value "        kbApi.getStats(),"  
Add-Content -Path $outPath -Value "      ]);"  
Add-Content -Path $outPath -Value "      setDocuments(filesRes.files);"  
Add-Content -Path $outPath -Value "      setStats(statsRes);"  
Add-Content -Path $outPath -Value "    } catch (err) {"  
Add-Content -Path $outPath -Value "      const msg = err instanceof Error ? err.message : 'Failed to load data';"  
Add-Content -Path $outPath -Value "      setError(msg);"  
Add-Content -Path $outPath -Value "    } finally {"  
Add-Content -Path $outPath -Value "      setLoading(false);"  
Add-Content -Path $outPath -Value "    }"  
Add-Content -Path $outPath -Value "  }, []);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  useEffect(() =^> {"  
Add-Content -Path $outPath -Value "    loadData();"  
Add-Content -Path $outPath -Value "    return () =^> {"  
Add-Content -Path $outPath -Value "      pollingRefs.current.forEach((id) =^> clearInterval(id));"  
Add-Content -Path $outPath -Value "    };"  
Add-Content -Path $outPath -Value "  }, [loadData]);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const startPolling = useCallback((documentId: string, itemIndex: number) =^> {"  
Add-Content -Path $outPath -Value "    if (pollingRefs.current.has(documentId)) return;"  
Add-Content -Path $outPath -Value "    const intervalId = setInterval(async () =^> {"  
Add-Content -Path $outPath -Value "      try {"  
Add-Content -Path $outPath -Value "        const status = await kbApi.getStatus(documentId);"  
Add-Content -Path $outPath -Value "        setUploadItems((prev) =^>"  
Add-Content -Path $outPath -Value "          prev.map((item, idx) =^> {"  
Add-Content -Path $outPath -Value "            if (idx !== itemIndex) return item;"  
Add-Content -Path $outPath -Value "            if (status.ready) {"  
Add-Content -Path $outPath -Value "              clearInterval(pollingRefs.current.get(documentId)!);"  
Add-Content -Path $outPath -Value "              pollingRefs.current.delete(documentId);"  
Add-Content -Path $outPath -Value "              loadData();"  
Add-Content -Path $outPath -Value "              return { ...item, status: 'ready', chunkCount: status.chunk_count };"  
Add-Content -Path $outPath -Value "            }"  
Add-Content -Path $outPath -Value "            if (status.status === 'error') {"  
Add-Content -Path $outPath -Value "              clearInterval(pollingRefs.current.get(documentId)!);"  
Add-Content -Path $outPath -Value "              pollingRefs.current.delete(documentId);"  
Add-Content -Path $outPath -Value "              return { ...item, status: 'error', error: status.error ?? 'Processing failed' };"  
Add-Content -Path $outPath -Value "            }"  
Add-Content -Path $outPath -Value "            return { ...item, status: 'processing' };"  
Add-Content -Path $outPath -Value "          }),"  
Add-Content -Path $outPath -Value "        );"  
Add-Content -Path $outPath -Value "      } catch { /* ignore */ }"  
Add-Content -Path $outPath -Value "    }, 2000);"  
Add-Content -Path $outPath -Value "    pollingRefs.current.set(documentId, intervalId);"  
Add-Content -Path $outPath -Value "  }, [loadData]);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const handleFiles = useCallback("  
Add-Content -Path $outPath -Value "    async (files: File[]) =^> {"  
Add-Content -Path $outPath -Value "      if (files.length === 0) return;"  
Add-Content -Path $outPath -Value "      setActiveTab('upload');"  
Add-Content -Path $outPath -Value "      const newItems: UploadItem[] = files.map((f) =^> ({ file: f, status: 'pending' }));"  
Add-Content -Path $outPath -Value "      setUploadItems((prev) =^> [...newItems, ...prev]);"  
Add-Content -Path $outPath -Value "      for (let i = 0; i ^< newItems.length; i++) {"  
Add-Content -Path $outPath -Value "        const globalIdx = i;"  
Add-Content -Path $outPath -Value "        setUploadItems((prev) =^>"  
Add-Content -Path $outPath -Value "          prev.map((item, idx) =^> (idx === globalIdx ? { ...item, status: 'uploading' } : item)),"  
Add-Content -Path $outPath -Value "        );"  
Add-Content -Path $outPath -Value "        try {"  
Add-Content -Path $outPath -Value "          const result = await kbApi.upload(newItems[i].file);"  
Add-Content -Path $outPath -Value "          setUploadItems((prev) =^>"  
Add-Content -Path $outPath -Value "            prev.map((item, idx) =^>"  
Add-Content -Path $outPath -Value "              idx === globalIdx"  
Add-Content -Path $outPath -Value "                ? { ...item, status: 'processing', documentId: result.document_id }"  
Add-Content -Path $outPath -Value "                : item,"  
Add-Content -Path $outPath -Value "            ),"  
Add-Content -Path $outPath -Value "          );"  
Add-Content -Path $outPath -Value "          if (result.document_id) {"  
Add-Content -Path $outPath -Value "            startPolling(result.document_id, globalIdx);"  
Add-Content -Path $outPath -Value "          }"  
Add-Content -Path $outPath -Value "        } catch (err) {"  
Add-Content -Path $outPath -Value "          setUploadItems((prev) =^>"  
Add-Content -Path $outPath -Value "            prev.map((item, idx) =^>"  
Add-Content -Path $outPath -Value "              idx === globalIdx"  
Add-Content -Path $outPath -Value "                ? { ...item, status: 'error', error: err instanceof Error ? err.message : 'Upload failed' }"  
Add-Content -Path $outPath -Value "                : item,"  
Add-Content -Path $outPath -Value "            ),"  
Add-Content -Path $outPath -Value "          );"  
Add-Content -Path $outPath -Value "        }"  
Add-Content -Path $outPath -Value "      }"  
Add-Content -Path $outPath -Value "    },"  
Add-Content -Path $outPath -Value "    [startPolling],"  
Add-Content -Path $outPath -Value "  );" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const handleDelete = useCallback(async (id: string) =^> {"  
Add-Content -Path $outPath -Value "    try {"  
Add-Content -Path $outPath -Value "      await kbApi.deleteFile(id);"  
Add-Content -Path $outPath -Value "      setDocuments((prev) =^> prev.filter((d) =^> d.id !== id));"  
Add-Content -Path $outPath -Value "      if (stats) setStats({ ...stats, total_documents: stats.total_documents - 1 });"  
Add-Content -Path $outPath -Value "    } catch (err) {"  
Add-Content -Path $outPath -Value "      setError(err instanceof Error ? err.message : 'Delete failed');"  
Add-Content -Path $outPath -Value "    }"  
Add-Content -Path $outPath -Value "  }, [stats]);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const categories = useMemo("  
Add-Content -Path $outPath -Value "    () =^> (stats ? ['all', ...Object.keys(stats.categories)] : ['all']),"  
Add-Content -Path $outPath -Value "    [stats],"  
Add-Content -Path $outPath -Value "  );"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const filteredDocs = useMemo(() =^> {"  
Add-Content -Path $outPath -Value "    let docs = activeCategory === 'all' ? documents : documents.filter((d) =^> d.category === activeCategory);"  
Add-Content -Path $outPath -Value "    if (searchQuery.trim()) {"  
Add-Content -Path $outPath -Value "      const q = searchQuery.toLowerCase();"  
Add-Content -Path $outPath -Value "      docs = docs.filter("  
Add-Content -Path $outPath -Value "        (d) =^>"  
Add-Content -Path $outPath -Value "          d.filename.toLowerCase().includes(q) ^|^|"  
Add-Content -Path $outPath -Value "          (d.title ?? '').toLowerCase().includes(q) ^|^|"  
Add-Content -Path $outPath -Value "          (d.category ?? '').toLowerCase().includes(q),"  
Add-Content -Path $outPath -Value "      );"  
Add-Content -Path $outPath -Value "    }"  
Add-Content -Path $outPath -Value "    return docs;"  
Add-Content -Path $outPath -Value "  }, [documents, activeCategory, searchQuery]);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const recentDocs = useMemo("  
Add-Content -Path $outPath -Value "    () =^>"  
Add-Content -Path $outPath -Value "      [...documents]"  
Add-Content -Path $outPath -Value "        .sort((a, b) =^> new Date(b.created_at).getTime() - new Date(a.created_at).getTime())"  
Add-Content -Path $outPath -Value "        .slice(0, 6),"  
Add-Content -Path $outPath -Value "    [documents],"  
Add-Content -Path $outPath -Value "  );"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const bookmarkedDocs = useMemo("  
Add-Content -Path $outPath -Value "    () =^> documents.filter((d) =^> bookmarkedIds.has(d.id)),"  
Add-Content -Path $outPath -Value "    [documents, bookmarkedIds],"  
Add-Content -Path $outPath -Value "  );"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const handleBookmark = useCallback((id: string) =^> {"  
Add-Content -Path $outPath -Value "    setBookmarkedIds((prev) =^> {"  
Add-Content -Path $outPath -Value "      const next = new Set(prev);"  
Add-Content -Path $outPath -Value "      if (next.has(id)) next.delete(id);"  
Add-Content -Path $outPath -Value "      else next.add(id);"  
Add-Content -Path $outPath -Value "      return next;"  
Add-Content -Path $outPath -Value "    });"  
Add-Content -Path $outPath -Value "  }, []);" 
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  const dot = isDark ? 'rgba(255,255,255,0.025)' : 'rgba(0,0,0,0.03)';"  
Add-Content -Path $outPath -Value ""  
Add-Content -Path $outPath -Value "  return ("  
Add-Content -Path $outPath -Value "    ^<div"  
Add-Content -Path $outPath -Value "      style={{"  
Add-Content -Path $outPath -Value "        minHeight: '100vh',"  
Add-Content -Path $outPath -Value "        backgroundColor: colors.background,"  
Add-Content -Path $outPath -Value "        backgroundImage: ["  
Add-Content -Path $outPath -Value "          'radial-gradient(ellipse 120%% 50%% at 60%% -8%%, rgba(254,192,15,0.045) 0%%, transparent 55%%)',"  
Add-Content -Path $outPath -Value "          'radial-gradient(' + dot + ' 1px, transparent 1px)',"  
Add-Content -Path $outPath -Value "        ].join(', '),"  
Add-Content -Path $outPath -Value "        backgroundSize: 'auto, 24px 24px',"  
Add-Content -Path $outPath -Value "        fontFamily: `"'Instrument Sans', 'Quicksand', sans-serif`","  
Add-Content -Path $outPath -Value "        color: colors.text,"  
Add-Content -Path $outPath -Value "      }}"  
Add-Content -Path $outPath -Value "    ^>" 
Add-Content -Path $outPath -Value "      ^<div style={{ height: '1px', background: 'linear-gradient(90deg, transparent 0%%, var(--accent) 45%%, rgba(254,192,15,0.25) 65%%, transparent 100%%)', opacity: 0.45 }} /^>"  
Add-Content -Path $outPath -Value "      ^<div style={{ borderBottom: '1px solid ' + colors.border, padding: isMobile ? '24px 20px 0' : '40px 52px 0' }}^>"  
Add-Content -Path $outPath -Value "        ^<div style={{ maxWidth: '1360px', margin: '0 auto' }}^>"  
Add-Content -Path $outPath -Value "          ^<div style={{ display: 'flex', alignItems: isMobile ? 'flex-start' : 'center', justifyContent: 'space-between', gap: '16px', flexDirection: isMobile ? 'column' : 'row', marginBottom: '24px' }}^>"  
Add-Content -Path $outPath -Value "            ^<div^>"  
Add-Content -Path $outPath -Value "              ^<div style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', background: 'rgba(254,192,15,0.08)', border: '1px solid rgba(254,192,15,0.2)', borderRadius: '100px', padding: '4px 14px 4px 10px', marginBottom: '14px' }}^>"  
Add-Content -Path $outPath -Value "                ^<div style={{ width: 5, height: 5, borderRadius: '50%%', background: 'var(--accent)', animation: 'kb-pulse 2.4s ease-in-out infinite' }} /^>"  
Add-Content -Path $outPath -Value "                ^<span style={{ fontFamily: `"'DM Mono', monospace`", fontSize: '9px', letterSpacing: '0.16em', textTransform: 'uppercase', color: 'var(--accent)' }}^>"  
Add-Content -Path $outPath -Value "                  Knowledge Base {stats ? stats.total_documents + ' docs' : 'Loading'}"  
Add-Content -Path $outPath -Value "                ^</span^>"  
Add-Content -Path $outPath -Value "              ^</div^>" 
Add-Content -Path $outPath -Value "              ^<h1 style={{ fontFamily: `"'Syne', sans-serif`", fontSize: isMobile ? '28px' : '42px', fontWeight: 800, letterSpacing: '-0.025em', lineHeight: 1.08, color: colors.text, margin: 0 }}^>"  
Add-Content -Path $outPath -Value "                Knowledge ^<span style={{ color: 'var(--accent)' }}^>Base^</span^>"  
Add-Content -Path $outPath -Value "              ^</h1^>"  
Add-Content -Path $outPath -Value "              ^<p style={{ fontSize: '13px', color: colors.textMuted, lineHeight: 1.7, margin: '6px 0 0' }}^>Upload, search, and manage your documents^</p^>"  
Add-Content -Path $outPath -Value "            ^</div^>"  
Add-Content -Path $outPath -Value "            ^<div style={{ display: 'flex', gap: '8px', flexShrink: 0 }}^>"  
Add-Content -Path $outPath -Value "              ^<button onClick={loadData} title=`"Refresh`" style={{ width: 38, height: 38, borderRadius: '9px', border: '1px solid ' + colors.border, background: colors.cardBg, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.textMuted, boxShadow: colors.shadow }}^>"  
Add-Content -Path $outPath -Value "                ^<RefreshCw size={14} /^>"  
Add-Content -Path $outPath -Value "              ^</button^>"  
Add-Content -Path $outPath -Value "              ^<button onClick={() =^> setShowFeedback(true)} style={{ height: 38, padding: '0 16px', borderRadius: '9px', border: '1px solid ' + colors.border, background: colors.cardBg, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '7px', color: colors.textMuted, fontFamily: `"'Syne', sans-serif`", fontSize: '11px', fontWeight: 600, letterSpacing: '0.07em', textTransform: 'uppercase', boxShadow: colors.shadow }}^>"  
Add-Content -Path $outPath -Value "                ^<MessageSquarePlus size={13} /^>"  
Add-Content -Path $outPath -Value "                {!isMobile ^&^& 'Feedback'}"  
Add-Content -Path $outPath -Value "              ^</button^>"  
Add-Content -Path $outPath -Value "            ^</div^>"  
Add-Content -Path $outPath -Value "          ^</div^>" 
Add-Content -Path $outPath -Value "          {stats ^&^& !loading ^&^& ("  
Add-Content -Path $outPath -Value "            ^<div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '4px' }}^>"  
Add-Content -Path $outPath -Value "              {["  
Add-Content -Path $outPath -Value "                { label: 'Documents', value: stats.total_documents, icon: FileText, color: 'var(--accent)' },"  
Add-Content -Path $outPath -Value "                { label: 'Total Size', value: formatFileSize(stats.total_size), icon: HardDrive, color: '#60A5FA' },"  
