Add-Content -Path $outPath -Value "                      return ("  
Add-Content -Path $outPath -Value "                        ^<div key={doc.id} style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 22px', borderBottom: idx ^< filteredDocs.length - 1 ? '1px solid ' + colors.border : 'none', transition: 'background .15s' }} onMouseEnter={(e) =^> (e.currentTarget.style.background = colors.hoverBg)} onMouseLeave={(e) =^> (e.currentTarget.style.background = 'transparent')}^>"  
Add-Content -Path $outPath -Value "                          ^<div style={{ width: 38, height: 38, borderRadius: '9px', background: fColor + '14', border: '1px solid ' + fColor + '30', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, cursor: 'pointer' }} onClick={() =^> setViewerDoc(doc)}^>"  
Add-Content -Path $outPath -Value "                            ^<FileText size={16} color={fColor} /^>"  
Add-Content -Path $outPath -Value "                          ^</div^>" 
Add-Content -Path $outPath -Value "                          ^<div style={{ flex: 1, minWidth: 0, cursor: 'pointer' }} onClick={() =^> setViewerDoc(doc)}^>"  
Add-Content -Path $outPath -Value "                            ^<p style={{ color: colors.text, fontSize: '13px', fontWeight: 600, margin: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}^>{doc.filename}^</p^>"  
Add-Content -Path $outPath -Value "                            ^<div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginTop: '3px', flexWrap: 'wrap' }}^>"  
Add-Content -Path $outPath -Value "                              {doc.category ^&^& ^<span style={{ fontSize: '9px', padding: '2px 7px', borderRadius: '4px', background: cc.bg, color: cc.text, fontFamily: `"'DM Mono', monospace`", letterSpacing: '0.06em', textTransform: 'uppercase' }}^>{doc.category}^</span^>}"  
Add-Content -Path $outPath -Value "                              ^<span style={{ color: colors.textMuted, fontSize: '11px' }}^>{formatFileSize(doc.file_size ?? doc.size)}^</span^>"  
Add-Content -Path $outPath -Value "                              {doc.chunk_count != null ^&^& ^<span style={{ color: colors.textMuted, fontSize: '11px', fontFamily: `"'DM Mono', monospace`" }}^>{doc.chunk_count} chunks^</span^>}"  
Add-Content -Path $outPath -Value "                              ^<span style={{ color: colors.textMuted, fontSize: '11px' }}^>{new Date(doc.created_at).toLocaleDateString()}^</span^>"  
Add-Content -Path $outPath -Value "                            ^</div^>"  
Add-Content -Path $outPath -Value "                          ^</div^>"  
Add-Content -Path $outPath -Value "                          ^<div style={{ display: 'flex', gap: '4px', flexShrink: 0 }}^>"  
Add-Content -Path $outPath -Value "                            ^<button onClick={() =^> handleBookmark(doc.id)} style={{ width: '32px', height: '32px', borderRadius: '7px', border: '1px solid ' + (bookmarkedIds.has(doc.id) ? 'var(--accent)' : colors.border), background: 'transparent', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: bookmarkedIds.has(doc.id) ? 'var(--accent)' : colors.textMuted }}^>"  
Add-Content -Path $outPath -Value "                              {bookmarkedIds.has(doc.id) ? ^<BookmarkCheck size={13} /^> : ^<Bookmark size={13} /^>}"  
Add-Content -Path $outPath -Value "                            ^</button^>"  
Add-Content -Path $outPath -Value "                            ^<button onClick={() =^> setViewerDoc(doc)} style={{ width: '32px', height: '32px', borderRadius: '7px', border: '1px solid ' + colors.border, background: 'transparent', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: colors.textMuted }} title=`"View document`"^>^<Search size={13} /^>^</button^>"  
Add-Content -Path $outPath -Value "                            ^<button onClick={() =^> handleDelete(doc.id)} style={{ width: '32px', height: '32px', borderRadius: '7px', border: '1px solid rgba(239,68,68,0.3)', background: 'rgba(239,68,68,0.06)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#ef4444' }} title=`"Delete document`"^>^<X size={13} /^>^</button^>"  
Add-Content -Path $outPath -Value "                          ^</div^>"  
Add-Content -Path $outPath -Value "                        ^</div^>"  
Add-Content -Path $outPath -Value "                      );"  
Add-Content -Path $outPath -Value "                    })"  
Add-Content -Path $outPath -Value "                  )}"  
Add-Content -Path $outPath -Value "                ^</div^>"  
Add-Content -Path $outPath -Value "              ^</div^>"  
Add-Content -Path $outPath -Value "            )}" 
